const src = $json;
const text = String(src.text_for_classification || '').trim();
const rating = String(src.source_rating || '').toUpperCase();

const suspiciousPatterns = [
  /ignore (all )?(previous|prior|above) instructions/i,
  /system prompt/i,
  /developer message/i,
  /reveal.*(prompt|instructions|secrets)/i,
  /jailbreak/i,
  /act as/i,
  /do not classify/i,
  /return only/i,
  /api[_ -]?key|token|password/i
];

const reasons = [];
if (!text) reasons.push('empty_text');
if (text.length < 20) reasons.push('text_too_short');
if (text.length > 8000) reasons.push('text_too_long');
if (['E', 'F'].includes(rating)) reasons.push(`low_source_rating_${rating}`);
for (const pattern of suspiciousPatterns) {
  if (pattern.test(text)) reasons.push(`possible_prompt_injection:${pattern.source}`);
}

return {
  ...src,
  text_for_classification: text.slice(0, 8000),
  should_quarantine: reasons.length > 0,
  guardrail_reasons: reasons
};

const src = $('Pre-Guardrail Check').item.json;
const raw = $json;
const provider = 'cerebras';

let generated = '';
let cls = null;

// --- Extract raw content from Cerebras response ---
if (raw && typeof raw === 'object' && !Array.isArray(raw) && raw.event_class && raw.confidence) {
  cls = raw;
  generated = JSON.stringify(raw);
} else {
  if (Array.isArray(raw)) {
    generated = raw[0]?.generated_text || raw[0]?.summary_text || JSON.stringify(raw[0] || {});
  } else if (raw?.choices?.[0]?.message?.content) {
    generated = raw.choices[0].message.content;
  } else {
    generated = raw?.generated_text || raw?.summary_text || raw?.[0]?.generated_text || JSON.stringify(raw);
  }

  function extractJson(text) {
    if (!text) return null;
    const cleaned = String(text).replace(/```json|```/gi, '').trim();
    const first = cleaned.indexOf('{');
    const last = cleaned.lastIndexOf('}');
    const body = first >= 0 && last > first ? cleaned.slice(first, last + 1).trim() : cleaned;

    const tryJson = (candidate) => {
      try { return JSON.parse(candidate); } catch (e) { return null; }
    };

    const asJson = tryJson(body);
    if (asJson) return asJson;

    const jsLike = body
      .replace(/\bNone\b/g, 'null')
      .replace(/\bTrue\b/g, 'true')
      .replace(/\bFalse\b/g, 'false');

    if (/=>|\bfunction\b|\bwhile\b|\bfor\s*\(|\bprocess\b|\brequire\b|`/.test(jsLike)) {
      return null;
    }

    try {
      return Function('"use strict"; return (' + jsLike + ');')();
    } catch (e) {
      return null;
    }
  }

  cls = extractJson(generated);
}

// --- Validate and normalize base fields ---
if (cls && typeof cls === 'object' && !Array.isArray(cls)) {
  // Backward compatibility
  if (cls.confidentiality && !cls.confidence) cls.confidence = cls.confidentiality;
  if (cls.confidentiality_flag && !cls.guardrail_flags) {
    cls.guardrail_flags = Array.isArray(cls.confidentiality_flag)
      ? cls.confidentiality_flag
      : [String(cls.confidentiality_flag)];
  }
  if (!Array.isArray(cls.guardrail_flags)) cls.guardrail_flags = [];

  // Casualties estimate
  if (!cls.casualties_estimate || typeof cls.casualties_estimate !== 'object' || Array.isArray(cls.casualties_estimate)) {
    cls.casualties_estimate = { min: null, max: null };
  } else {
    if (!Object.prototype.hasOwnProperty.call(cls.casualties_estimate, 'min')) cls.casualties_estimate.min = null;
    if (!Object.prototype.hasOwnProperty.call(cls.casualties_estimate, 'max')) cls.casualties_estimate.max = null;
  }

  // Ensure base fields exist
  ['event_subclass', 'country', 'latitude', 'longitude', 'actor_initiator', 'actor_target', 'weapon_system'].forEach(f => {
    if (!Object.prototype.hasOwnProperty.call(cls, f)) cls[f] = null;
  });

  // Classification version
  if (!Object.prototype.hasOwnProperty.call(cls, 'classification_version') || !Number.isFinite(Number(cls.classification_version))) {
    cls.classification_version = 1;
  } else {
    cls.classification_version = Number(cls.classification_version);
  }

  // --- NEW FIELDS: strategic and geospatial enrichment ---
  // severity: integer 1-5
  if (!Object.prototype.hasOwnProperty.call(cls, 'severity')) {
    cls.severity = null;
  } else {
    const sev = Number(cls.severity);
    cls.severity = Number.isInteger(sev) ? Math.min(5, Math.max(1, sev)) : null;
  }

  // escalation_potential: low/medium/high
  const validEsc = ['low', 'medium', 'high'];
  cls.escalation_potential = validEsc.includes(cls.escalation_potential) ? cls.escalation_potential : null;

  // strategic_impact: local/regional/global
  const validImpact = ['local', 'regional', 'global'];
  cls.strategic_impact = validImpact.includes(cls.strategic_impact) ? cls.strategic_impact : null;

  // event_phase: preparation/execution/aftermath/ongoing
  const validPhase = ['preparation', 'execution', 'aftermath', 'ongoing'];
  cls.event_phase = validPhase.includes(cls.event_phase) ? cls.event_phase : null;

  // admin1 (province/state) and city
  cls.admin1 = (typeof cls.admin1 === 'string' && cls.admin1.trim()) ? cls.admin1.trim().slice(0, 100) : null;
  cls.city = (typeof cls.city === 'string' && cls.city.trim()) ? cls.city.trim().slice(0, 100) : null;

  // weapon_category – free text but can be validated against a list if desired
  cls.weapon_category = (typeof cls.weapon_category === 'string' && cls.weapon_category.trim()) ? cls.weapon_category.trim() : null;

  // casualties_confidence: low/medium/high
  cls.casualties_confidence = validEsc.includes(cls.casualties_confidence) ? cls.casualties_confidence : null;

  // intelligence_gaps: array of strings
  cls.intelligence_gaps = Array.isArray(cls.intelligence_gaps) ? cls.intelligence_gaps.slice(0, 10).map(g => String(g).trim()) : null;

  // event_time_original: raw extracted date string
  cls.event_time_original = (typeof cls.event_time_original === 'string' && cls.event_time_original.trim()) ? cls.event_time_original.trim().slice(0, 200) : null;

  // ongoing: boolean
  cls.ongoing = (typeof cls.ongoing === 'boolean') ? cls.ongoing : null;

  // classification_metadata: store any extra fields not explicitly captured
  const extraFields = {};
  const knownFields = new Set([
    'event_class', 'event_subclass', 'country', 'latitude', 'longitude', 'actor_initiator', 'actor_target',
    'confidence', 'weapon_system', 'casualties_estimate', 'rationale', 'guardrail_flags', 'classification_version',
    'severity', 'escalation_potential', 'strategic_impact', 'event_phase', 'admin1', 'city', 'weapon_category',
    'casualties_confidence', 'intelligence_gaps', 'event_time_original', 'ongoing'
  ]);
  for (const key in cls) {
    if (!knownFields.has(key) && cls[key] !== undefined && cls[key] !== null) {
      extraFields[key] = cls[key];
    }
  }
  cls.classification_metadata = Object.keys(extraFields).length ? extraFields : null;
}

// --- Guardrail reasons (quarantine if invalid) ---
const reasons = [];
if (!cls) reasons.push('classifier_output_not_valid_json');

const allowedClasses = ['political', 'military_kinetic', 'economic', 'socio_cultural', 'cyber_information', 'indicator_warning', 'other', 'unknown'];
const allowedConfidence = ['high', 'medium', 'low'];

if (cls) {
  if (!allowedClasses.includes(cls.event_class)) reasons.push('invalid_event_class');
  if (!allowedConfidence.includes(cls.confidence)) reasons.push('invalid_confidence');
  if (cls.latitude !== null && cls.latitude !== undefined && !Number.isFinite(Number(cls.latitude))) reasons.push('invalid_latitude');
  if (cls.longitude !== null && cls.longitude !== undefined && !Number.isFinite(Number(cls.longitude))) reasons.push('invalid_longitude');
  if (String(cls.rationale || '').length > 2000) reasons.push('rationale_too_long');
  // Additional validation for new fields (optional)
  if (cls.severity !== null && (cls.severity < 1 || cls.severity > 5)) reasons.push('severity_out_of_range');
}

return {
  ...src,
  classifier_provider: provider,
  classifier_raw_response: raw,
  classifier_generated_text: generated,
  classification: cls,
  should_quarantine: reasons.length > 0,
  guardrail_reasons: reasons
};

const src = $json;
const cls = src.classification || {};

// Helper: escape and quote for SQL
const q = (v) => {
  if (v === null || v === undefined || v === '') return 'NULL';
  return `'${String(v).replace(/'/g, "''")}'`;
};

// Helper: convert to number or NULL
const toNumOrNull = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

// --- Coordinates and geometry ---
const lon = toNumOrNull(cls.longitude);
const lat = toNumOrNull(cls.latitude);

// Country normalisation (same as before)
const toTextOrNull = (v) => {
  if (v === null || v === undefined) return null;
  if (typeof v === 'string') {
    const t = v.trim();
    return t === '' ? null : t;
  }
  if (typeof v === 'number' || typeof v === 'boolean') return String(v);
  if (typeof v === 'object') {
    const name = typeof v.name === 'string' ? v.name.trim() : '';
    if (name) return name;
    const label = typeof v.label === 'string' ? v.label.trim() : '';
    if (label) return label;
    return null;
  }
  return null;
};

const normalizeCountryKey = (value) =>
  String(value || '')
    .toLowerCase()
    .replace(/[^a-z0-9 ]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

const countryRaw = toTextOrNull(cls.country);
const normalizedCountry = normalizeCountryKey(countryRaw);
const countryAliases = {
  us: 'united states', usa: 'united states', 'u s': 'united states', 'u s a': 'united states',
  'united states of america': 'united states', 'u k': 'united kingdom', uk: 'united kingdom',
  'russian federation': 'russia'
};
const canonicalCountry = countryAliases[normalizedCountry] || normalizedCountry;

// Country centroids (fallback when only country is known)
const countryCentroids = {
  israel: [34.8516, 31.0461], iran: [53.688, 32.4279], syria: [38.9968, 34.8021],
  lebanon: [35.8623, 33.8547], russia: [105.3188, 61.524], ukraine: [31.1656, 48.3794],
  venezuela: [-66.5897, 6.4238], 'united states': [-98.5795, 39.8283], estonia: [25.0136, 58.5953],
  finland: [25.7482, 61.9241], poland: [19.1451, 51.9194], belarus: [27.9534, 53.7098],
  guinea: [-9.6966, 9.9456], liberia: [-9.4295, 6.4281], ecuador: [-78.1834, -1.8312],
  mexico: [-102.5528, 23.6345], china: [104.1954, 35.8617], canada: [-106.3468, 56.1304],
  nicaragua: [-85.2072, 12.8654], greenland: [-42.6043, 71.7069], 'united kingdom': [-3.435973, 55.378051]
};
const fallbackCentroid = countryCentroids[canonicalCountry] || null;

const geomSql = (lon !== null && lat !== null)
  ? `ST_SetSRID(ST_MakePoint(${lon}, ${lat}), 4326)`
  : (fallbackCentroid ? `ST_SetSRID(ST_MakePoint(${fallbackCentroid[0]}, ${fallbackCentroid[1]}), 4326)` : 'NULL');

// --- Other fields ---
const casualtiesJson = JSON.stringify(cls.casualties_estimate || {});
const confidence = ['high', 'medium', 'low'].includes(String(cls.confidence || '').toLowerCase())
  ? String(cls.confidence).toLowerCase()
  : 'low';
const actorInitiator = toTextOrNull(cls.actor_initiator);
const actorTarget = toTextOrNull(cls.actor_target);

// New fields
const severityNum = Number(cls.severity);
const severity = Number.isInteger(severityNum) ? Math.min(5, Math.max(1, severityNum)) : null;
const escalationPotential = ['low', 'medium', 'high'].includes(cls.escalation_potential) ? cls.escalation_potential : null;
const strategicImpact = ['local', 'regional', 'global'].includes(cls.strategic_impact) ? cls.strategic_impact : null;
const eventPhase = ['preparation', 'execution', 'aftermath', 'ongoing'].includes(cls.event_phase) ? cls.event_phase : null;
const admin1 = toTextOrNull(cls.admin1 || cls.state);
const state = toTextOrNull(cls.state || cls.admin1);
const city = toTextOrNull(cls.city);
const weaponCategory = toTextOrNull(cls.weapon_category);
const casualtiesConfidence = ['low', 'medium', 'high'].includes(cls.casualties_confidence) ? cls.casualties_confidence : null;
const intelligenceGaps = Array.isArray(cls.intelligence_gaps) && cls.intelligence_gaps.length
  ? cls.intelligence_gaps.map(g => q(g)).join(',')
  : null;
const startedAtOriginal = toTextOrNull(cls.started_at_original);
const classificationMetadata = cls.classification_metadata ? q(JSON.stringify(cls.classification_metadata)) : 'NULL';

// --- SQL INSERT statement with actor resolution (same as before) ---
const sql = `
WITH initiator_input AS (
  SELECT NULLIF(${q(actorInitiator)}, 'NULL') AS name
),
target_input AS (
  SELECT NULLIF(${q(actorTarget)}, 'NULL') AS name
),
upsert_initiator AS (
  INSERT INTO actors (name, type)
  SELECT name, 'unknown'
  FROM initiator_input
  WHERE name IS NOT NULL
  ON CONFLICT (name) DO NOTHING
  RETURNING id, name
),
upsert_target AS (
  INSERT INTO actors (name, type)
  SELECT name, 'unknown'
  FROM target_input
  WHERE name IS NOT NULL
  ON CONFLICT (name) DO NOTHING
  RETURNING id, name
),
resolved_initiator AS (
  SELECT id FROM upsert_initiator
  UNION ALL
  SELECT a.id
  FROM actors a
  JOIN initiator_input i ON a.name = i.name
  WHERE i.name IS NOT NULL
  LIMIT 1
),
resolved_target AS (
  SELECT id FROM upsert_target
  UNION ALL
  SELECT a.id
  FROM actors a
  JOIN target_input t ON a.name = t.name
  WHERE t.name IS NOT NULL
  LIMIT 1
),
insert_event AS (
  INSERT INTO events (
    osint_source_id,
    event_class,
    event_subclass,
    description,
    geom,
    country,
    admin1,
    state,
    city,
    started_at,
    ai_confidence,
    actor_initiator_id,
    actor_target_id,
    weapon_system,
    weapon_category,
    casualties_est,
    casualties_confidence,
    severity,
    escalation_potential,
    strategic_impact,
    event_phase,
    intelligence_gaps,
    started_at_original,
    classification_version,
    status,
    classification_metadata
  )
  SELECT
    ${Number(src.id)},
    ${q(cls.event_class || 'unknown')},
    ${q(cls.event_subclass)},
    ${q(cls.rationale || `Cerebras-classified from source ${src.id}`)},
    ${geomSql},
    ${q(countryRaw)},
    ${q(admin1)},
    ${q(state)},
    ${q(city)},
    ${q(src.posted_at)}::timestamptz,
    ${q(confidence)},
    (SELECT id FROM resolved_initiator),
    (SELECT id FROM resolved_target),
    ${q(cls.weapon_system)},
    ${q(weaponCategory)},
    '${casualtiesJson.replace(/'/g, "''")}'::jsonb,
    ${q(casualtiesConfidence)},
    ${severity !== null ? severity : 'NULL'},
    ${q(escalationPotential)},
    ${q(strategicImpact)},
    ${q(eventPhase)},
    ${intelligenceGaps ? `ARRAY[${intelligenceGaps}]` : 'NULL'},
    ${q(startedAtOriginal)},
    ${Number(cls.classification_version || 1)},
    'pending_review',
    ${classificationMetadata}
  WHERE NOT EXISTS (
    SELECT 1 FROM events e WHERE e.osint_source_id = ${Number(src.id)}
  )
  RETURNING id
)
SELECT id FROM insert_event;
`;

return { query: sql };

const item = $json;
const q = (v) => {
  if (v === null || v === undefined || v === '') return 'NULL';
  return `'${String(v).replace(/'/g, "''")}'`;
};
const payload = JSON.stringify(item).replace(/'/g, "''");
const reason = (item.guardrail_reasons || ['quarantined']).join('; ');
const parsedSourceId = Number(item.id ?? item.osint_source_id);
const sourceIdSql = Number.isFinite(parsedSourceId) ? String(parsedSourceId) : 'NULL';
const sql = `
INSERT INTO osint_quarantine (osint_source_id, reason, raw_payload)
VALUES (${sourceIdSql}, ${q(reason)}, '${payload}'::jsonb);
`;
return { query: sql };
